import React, { useEffect, useMemo, useState } from 'react';
import { createRoot } from 'react-dom/client';
import axios from 'axios';
import { io } from 'socket.io-client';
import './style.css';

const API = 'http://localhost:5000/api';
const socket = io('http://localhost:5000');

function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user') || 'null'));
  const [token, setToken] = useState(localStorage.getItem('token') || '');
  const [complaints, setComplaints] = useState([]);
  const [staff, setStaff] = useState([]);
  const [message, setMessage] = useState('');
  const [filter, setFilter] = useState({ status: 'All', category: 'All', search: '' });
  const [authMode, setAuthMode] = useState('login');
  const [auth, setAuth] = useState({ name: '', email: 'admin@test.com', password: '123456', role: 'admin', location: 'Admin Block' });
  const [form, setForm] = useState({ title: '', description: '', category: 'Electrical', priority: '', location: '' });

  const headers = { Authorization: `Bearer ${token}` };

  async function loadData() {
    if (!token) return;
    try {
      const res = await axios.get(`${API}/complaints`, { headers });
      setComplaints(res.data);
      if (user?.role === 'admin') {
        const s = await axios.get(`${API}/users/staff`, { headers });
        setStaff(s.data);
      }
    } catch (e) { setMessage(e.response?.data?.message || 'Failed to load data'); }
  }

  useEffect(() => { loadData(); }, [token]);
  useEffect(() => {
    socket.on('complaintsUpdated', () => loadData());
    return () => socket.off('complaintsUpdated');
  });

  async function submitAuth(e) {
    e.preventDefault();
    try {
      if (authMode === 'signup') {
        await axios.post(`${API}/auth/signup`, auth);
        setMessage('Signup successful. Please login.');
        setAuthMode('login');
        return;
      }
      const res = await axios.post(`${API}/auth/login`, { email: auth.email, password: auth.password });
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data.user));
      setToken(res.data.token); setUser(res.data.user); setMessage('Login successful');
    } catch (e) { setMessage(e.response?.data?.message || 'Auth failed'); }
  }

  async function createComplaint(e) {
    e.preventDefault();
    try {
      await axios.post(`${API}/complaints`, form, { headers });
      setForm({ title: '', description: '', category: 'Electrical', priority: '', location: '' });
      setMessage('Complaint created successfully');
    } catch (e) { setMessage(e.response?.data?.message || 'Failed to create complaint'); }
  }

  async function assignComplaint(id, staffId) {
    await axios.put(`${API}/complaints/${id}/assign`, { staffId }, { headers });
  }
  async function updateStatus(id, status) {
    await axios.put(`${API}/complaints/${id}/status`, { status }, { headers });
  }
  async function deleteComplaint(id) {
    await axios.delete(`${API}/complaints/${id}`, { headers });
  }

  const filtered = useMemo(() => complaints.filter(c =>
    (filter.status === 'All' || c.status === filter.status) &&
    (filter.category === 'All' || c.category === filter.category) &&
    (c.title.toLowerCase().includes(filter.search.toLowerCase()) || c.location.toLowerCase().includes(filter.search.toLowerCase()))
  ), [complaints, filter]);

  const stats = {
    total: complaints.length,
    open: complaints.filter(c => c.status === 'Open').length,
    progress: complaints.filter(c => c.status === 'In Progress').length,
    resolved: complaints.filter(c => c.status === 'Resolved').length
  };

  if (!user) return <div className="loginPage"><div className="authCard">
    <h1>Smart Complaint Tracker</h1><p>Campus / Society Issue Tracking System</p>
    <div className="demoBox"><b>Demo:</b> admin@test.com / staff@test.com / student@test.com<br/>Password: 123456</div>
    <form onSubmit={submitAuth}>
      {authMode === 'signup' && <><input placeholder="Name" value={auth.name} onChange={e=>setAuth({...auth,name:e.target.value})}/><select value={auth.role} onChange={e=>setAuth({...auth,role:e.target.value})}><option value="user">User</option><option value="staff">Staff</option><option value="admin">Admin</option></select><input placeholder="Location" value={auth.location} onChange={e=>setAuth({...auth,location:e.target.value})}/></>}
      <input placeholder="Email" value={auth.email} onChange={e=>setAuth({...auth,email:e.target.value})}/>
      <input type="password" placeholder="Password" value={auth.password} onChange={e=>setAuth({...auth,password:e.target.value})}/>
      <button>{authMode === 'login' ? 'Login' : 'Signup'}</button>
    </form>
    <button className="linkBtn" onClick={()=>setAuthMode(authMode==='login'?'signup':'login')}>{authMode === 'login' ? 'Create account' : 'Back to login'}</button>
    {message && <p className="msg">{message}</p>}
  </div></div>;

  return <div><nav><h2>Smart Complaint Tracker</h2><span>{user.name} ({user.role})</span><button onClick={()=>{localStorage.clear();setUser(null);setToken('')}}>Logout</button></nav>
  <main>
    <section className="stats"><div><b>{stats.total}</b><span>Total</span></div><div><b>{stats.open}</b><span>Open</span></div><div><b>{stats.progress}</b><span>In Progress</span></div><div><b>{stats.resolved}</b><span>Resolved</span></div></section>
    {message && <p className="msg">{message}</p>}
    {(user.role === 'user' || user.role === 'admin') && <section className="panel"><h3>Raise Complaint</h3><form className="gridForm" onSubmit={createComplaint}><input placeholder="Title" value={form.title} onChange={e=>setForm({...form,title:e.target.value})}/><select value={form.category} onChange={e=>setForm({...form,category:e.target.value})}>{['Electrical','Plumbing','Internet','Cleaning','Furniture','Security'].map(x=><option key={x}>{x}</option>)}</select><select value={form.priority} onChange={e=>setForm({...form,priority:e.target.value})}><option value="">Auto Priority</option><option>Low</option><option>Medium</option><option>High</option></select><input placeholder="Location" value={form.location} onChange={e=>setForm({...form,location:e.target.value})}/><textarea placeholder="Description" value={form.description} onChange={e=>setForm({...form,description:e.target.value})}/><button>Create</button></form></section>}
    <section className="panel"><h3>Complaint Dashboard <span className="live">● Live</span></h3><div className="filters"><input placeholder="Search by title/location" onChange={e=>setFilter({...filter,search:e.target.value})}/><select onChange={e=>setFilter({...filter,status:e.target.value})}><option>All</option><option>Open</option><option>In Progress</option><option>Resolved</option></select><select onChange={e=>setFilter({...filter,category:e.target.value})}><option>All</option><option>Electrical</option><option>Plumbing</option><option>Internet</option><option>Cleaning</option><option>Furniture</option><option>Security</option></select></div><div className="cards">{filtered.map(c=><div className="card" key={c.id}><div className="cardHead"><h4>{c.title}</h4><span className={`badge ${c.status.replace(' ','')}`}>{c.status}</span></div><p>{c.description}</p><small>{c.category} • {c.priority} Priority • {c.location}</small><div className="actions">{(user.role==='staff'||user.role==='admin') && <select value={c.status} onChange={e=>updateStatus(c.id,e.target.value)}><option>Open</option><option>In Progress</option><option>Resolved</option></select>}{user.role==='admin' && <select value={c.assignedTo || ''} onChange={e=>assignComplaint(c.id,e.target.value)}><option value="">Assign Staff</option>{staff.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}</select>}{user.role==='admin' && <button className="danger" onClick={()=>deleteComplaint(c.id)}>Delete</button>}</div></div>)}</div></section>
  </main></div>;
}

createRoot(document.getElementById('root')).render(<App />);
